-- Theme system migration for feat/theme_system.
-- Base branch checked locally: main (no local master ref exists).
-- This is idempotent and keeps an existing non-default current theme unchanged.

BEGIN;

CREATE TABLE IF NOT EXISTS t_themes (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    name TEXT NOT NULL,
    code TEXT NOT NULL UNIQUE,
    description TEXT NOT NULL DEFAULT '',
    author TEXT NOT NULL DEFAULT '',
    files TEXT NOT NULL DEFAULT '{}',
    current_file TEXT NOT NULL DEFAULT 'home.html',
    status TEXT NOT NULL DEFAULT 'draft',
    is_current INTEGER NOT NULL DEFAULT 0,
    is_builtin INTEGER NOT NULL DEFAULT 0,
    version INTEGER NOT NULL DEFAULT 1,
    created_at INTEGER NOT NULL,
    updated_at INTEGER NOT NULL,
    deleted_at INTEGER
);

CREATE UNIQUE INDEX IF NOT EXISTS idx_themes_single_current
ON t_themes (is_current)
WHERE is_current = 1 AND deleted_at IS NULL;

UPDATE t_themes
SET name = 'tuft',
    description = '内置默认主题',
    author = 'swaves',
    files = '{"404.html":"{% extends \"layout_main.html\" %}\n{% block content %}\n<header>\n  <h1>页面找不到</h1>\n  <p>页面不存在，可能已被删除或地址写错了。</p>\n</header>\n\n<article>\n  <p>\n    返回 <a href=\"{{ ReturnURL }}\">来源页</a>重试，\n    或者返回 <a href=\"{{ GetBasePath() }}\">首页</a>\n  </p>\n  {% if ReqID %}<p><small>请求ID: {{ ReqID }}</small></p>{% endif %}\n</article>\n{% endblock %}\n","detail.html":"{% extends \"layout_main.html\" %}\n{% block content %}\n{% from \"macro_content.html\" import CategoryItem, TagList %}\n\n<header>\n  <h1>{{ Entity.Name }}</h1>\n\n  {% include \"inc_list_nav.html\" %}\n</header>\n\n{% if Entity.Description %}\n<section>\n  <p class=\"subtitle\">{{ Entity.Description }}</p>\n</section>\n{% endif %}\n\n<ul>\n  {% for Item in List %}\n  <li>\n    <a href=\"{{ Item.PermLink }}\">{{ Item.Title }}</a>\n    <span class=\"relation\">\n      {{ TagList(Item.Tags, true) }}\n      {% if (not IsCategory) and Item.Category %}\n        {{ CategoryItem(Item.Category, true) }}\n      {% endif %}\n    </span>\n    <span class=\"published\">{{ Item.CreatedAt | relativeTime }}</span>\n  </li>\n  {% else %}\n  <li>暂无文章</li>\n  {% endfor %}\n</ul>\n{% endblock %}\n","error.html":"{% extends \"layout_main.html\" %}\n{% block content %}\n<header>\n  <h1>页面异常</h1>\n  <p>请求处理失败，请稍后重试。</p>\n</header>\n\n<article>\n  <p>\n    <a href=\"{{ ReturnURL }}\">返回来源页，重试</a>\n    或者 <a href=\"{{ GetBasePath() }}\">返回首页</a>\n  </p>\n  {% if ReqID %}<p><small>请求ID: {{ ReqID }}</small></p>{% endif %}\n</article>\n{% endblock %}\n","home.html":"{% extends \"layout_main.html\" %}\n{% block content %}\n<header>\n  <h1>{{ Settings(\"site_title\") }}</h1>\n  {% include \"inc_nav.html\" %}\n</header>\n\n<section>\n<ul class=\"articles\">\n  {% for Article in Articles %}\n  <li>\n    <a href=\"{{ Article.PermLink }}\">{{ Article.Title }}</a>\n    <span class=\"published\">{{ Article.PublishedAt | relativeTime }}</span>\n  </li>\n  {% else %}\n  <li>暂无文章</li>\n  {% endfor %}\n</ul>\n</section>\n\n{% include \"inc_pagination.html\" %}\n{% endblock %}\n","inc_comment_count.html":"<a class=\"comment-count\" href=\"#comments\" title=\"评论数\" aria-label=\"评论数\">\n  {{ LucideIcon(\"message-square\", 16) }}\n  <span>{% if Count %}{{ Count }}{% else %}0{% endif %}</span>\n</a>\n","inc_comment_item.html":"{% set CommentCore = Comment.Comment or Comment %}\n{% set CommentParentAuthor = Comment.ParentAuthor or CommentCore.ParentAuthor %}\n{% set CommentChildren = Comment.Children %}\n<li class=\"comment-item\" id=\"comment-{{ CommentCore.ID }}\">\n  <div class=\"comment-card\">\n    <header class=\"comment-meta\">\n      <div class=\"comment-info\">\n        <img\n          class=\"comment-avatar\"\n          src=\"{{ GetAvatarImage(CommentCore.AuthorEmail, CommentCore.Author, 40) }}\"\n          alt=\"{{ CommentCore.Author }}\"\n          width=\"40\"\n          height=\"40\"\n        >\n        <div class=\"comment-meta-main\">\n          <strong class=\"comment-author\">{{ CommentCore.Author }}</strong>\n          <small class=\"comment-time\">· {{ CommentCore.CreatedAt | relativeTime }}</small>\n          {% if CommentCore.ParentID > 0 %}\n            <small class=\"comment-reply-to\">· 回复 @{{ CommentParentAuthor }}</small>\n          {% endif %}\n        </div>\n      </div>\n      <div class=\"comment-actions\">\n        <button\n                type=\"button\"\n                class=\"comment-reply-btn\"\n                data-comment-reply\n                data-comment-id=\"{{ CommentCore.ID }}\"\n                data-comment-author=\"{{ CommentCore.Author }}\"\n        >回复</button>\n      </div>\n    </header>\n    <div class=\"comment-body\">{{ CommentCore.Content }}</div>\n  </div>\n  {% if CommentChildren %}\n    <ol class=\"comment-children\">\n      {% for ChildComment in CommentChildren %}\n        {% set Comment = ChildComment %}\n        {% include \"inc_comment_item.html\" %}\n      {% endfor %}\n    </ol>\n  {% endif %}\n</li>\n","inc_comment_pagination.html":"<nav aria-label=\"评论分页导航\" class=\"pagination comment-pagination\">\n  {% if Pager %}\n    <div class=\"ivalign gap-1\">\n      {% if not Pager.HasPrev() %}\n        <span class=\"page-link page-link-prev\" tabindex=\"-1\">上一页</span>\n      {% else %}\n        <a class=\"page-link page-link-prev\" href=\"?page={{ Pager.PrevPage() }}&pageSize={{ Pager.PageSize }}#comments\" tabindex=\"-1\">上一页</a>\n      {% endif %}\n\n      {% for Item in Pager.GetPageItems() %}\n        {% if Item.Type == \"ellipsis\" %}\n          <span class=\"page-link\" aria-hidden=\"true\">…</span>\n        {% elif Item.Current %}\n          <span class=\"page-link\">{{ Item.Page }}</span>\n        {% else %}\n          <a class=\"page-link-num page-link\" href=\"?page={{ Item.Page }}&pageSize={{ Pager.PageSize }}#comments\">{{ Item.Page }}</a>\n        {% endif %}\n      {% endfor %}\n\n      {% if not Pager.HasNext() %}\n        <span class=\"page-link page-link-next\">下一页</span>\n      {% else %}\n        <a class=\"page-link page-link-next\" href=\"?page={{ Pager.NextPage() }}&pageSize={{ Pager.PageSize }}#comments\">下一页</a>\n      {% endif %}\n    </div>\n  {% endif %}\n</nav>\n","inc_ga.html":"<script async=\"\" src=\"https://www.googletagmanager.com/gtag/js?id={{ Settings(\"ga4_id\") }}\"></script><script>\n  window.dataLayer = window.dataLayer || [];\n  function gtag(){dataLayer.push(arguments);}\n  gtag(''js'', new Date());\n  gtag(''config'', ''{{ Settings(\"ga4_id\") }}'');\n</script>\n","inc_like_action.html":"<form method=\"post\" action=\"{{ UrlFor(''site.action.like'', postID=PostID) }}\" style=\"display:inline-flex;align-items: center\" data-like-form>\n  <input type=\"hidden\" name=\"return_url\" value=\"{{ UrlPath }}\">\n  <button title=\"点赞数\" type=\"submit\" data-like-button data-liked=\"{% if Liked %}1{% else %}0{% endif %}\" aria-label=\"点赞\">\n    {{ LucideIcon(\"heart\", 16) }}\n    <span data-like-count>{% if LikeCount %}{{ LikeCount }}{% else %}0{% endif %}</span>\n  </button>\n</form>\n<script>\n  (function () {\n    if (window.__swavesLikeAsyncInit) {\n      return;\n    }\n    window.__swavesLikeAsyncInit = true;\n\n    function toLikeCount(value) {\n      var count = Number.parseInt(value, 10);\n      if (Number.isNaN(count) || count < 0) {\n        return 0;\n      }\n      return count;\n    }\n\n    function updateLikeButton(button, likeCount, liked) {\n      var countEl = button.querySelector(\"[data-like-count]\");\n      if (countEl) {\n        countEl.textContent = String(likeCount);\n      }\n      button.dataset.liked = liked ? \"1\" : \"0\";\n    }\n\n    async function handleLikeSubmit(event) {\n      event.preventDefault();\n\n      var form = event.currentTarget;\n      var button = form.querySelector(\"[data-like-button]\");\n      if (!button || button.disabled) {\n        return;\n      }\n\n      var countEl = button.querySelector(\"[data-like-count]\");\n      var previousCount = countEl ? countEl.textContent : \"\";\n      var previousLiked = button.dataset.liked || \"0\";\n      button.disabled = true;\n\n      try {\n        var ret = await sfetchJSON(form.action, {\n          method: \"POST\",\n          body: new FormData(form)\n        });\n\n        if (!ret.ok || !ret.body) {\n          throw new Error(\"点赞请求失败\");\n        }\n        var result = ret.body;\n        updateLikeButton(button, toLikeCount(result.likeCount), !!result.liked);\n      } catch (error) {\n        if (countEl) {\n          countEl.textContent = previousCount;\n        }\n        button.dataset.liked = previousLiked;\n        if (window.console && typeof window.console.warn === \"function\") {\n          window.console.warn(\"like request failed\", error);\n        }\n      } finally {\n        button.disabled = false;\n      }\n    }\n\n    var forms = document.querySelectorAll(\"[data-like-form]\");\n    forms.forEach(function (form) {\n      form.addEventListener(\"submit\", handleLikeSubmit);\n    });\n  })();\n</script>\n","inc_list_nav.html":"<nav>\n  <a href=\"{{ GetBasePath() }}\">首页</a>\n    {% if IsCategory %}\n      / <a href=\"{{ GetCategoryPrefix() }}\">分类</a>\n    {% endif %}\n    {% if IsTag %}\n      / <a href=\"{{ GetTagPrefix() }}\">标签</a>\n    {% endif %}\n</nav>\n","inc_meta.html":"  {% if MetaDescription or Settings(''site_desc'') %}<meta name=\"description\" content=\"{{ MetaDescription or Settings(''site_desc'') }}\"/>{% endif %}\n  {% if MetaKeywords or Settings(''site_keywords'') %}<meta name=\"keywords\" content=\"{{ MetaKeywords or Settings(''site_keywords'') }}\"/>{% endif %}\n  {% if CanonicalURL %}<link rel=\"canonical\" href=\"{{ CanonicalURL | safe }}\">{% endif %}\n","inc_nav.html":"<nav>\n  <a href=\"{{ GetBasePath() }}\">首页</a>\n  /\n  <a href=\"{{ GetCategoryPrefix() }}\">分类</a>\n  /\n  <a href=\"{{ GetTagPrefix() }}\">标签</a>\n  {% if Pages %}\n    {% for Page in Pages %}\n      / <a href=\"{{ Page.PermLink }}\">{{ Page.Title }}</a>\n    {% endfor %}\n  {% endif %}\n  / <a href=\"{{ GetRSSUrl() }}\">RSS</a>\n  {% if IsLogin %}\n    / <a href=\"{{ GetDashUrl() }}\">管理</a>\n  {% endif %}\n</nav>\n","inc_pagination.html":"<nav aria-label=\"分页导航\" class=\"pagination\">\n  {% if Pager %}\n  <div class=\"ivalign gap-1\">\n    {% if not Pager.HasPrev() %}\n    <span class=\"page-link page-link-prev\" tabindex=\"-1\">上一页</span>\n    {% else %}\n    <a class=\"page-link page-link-prev\" href=\"?page={{ Pager.PrevPage() }}&pageSize={{ Pager.PageSize }}{% if SearchQueryEscaped %}&q={{ SearchQueryEscaped }}{% endif %}\" tabindex=\"-1\">上一页</a>\n    {% endif %}\n\n    {% for Item in Pager.GetPageItems() %}\n    {% if Item.Type == \"ellipsis\" %}\n    <span class=\"page-link\" aria-hidden=\"true\">…</span>\n    {% elif Item.Current %}\n    <span class=\"page-link\">{{ Item.Page }}</span>\n    {% else %}\n    <a class=\"page-link-num page-link\" href=\"?page={{ Item.Page }}&pageSize={{ Pager.PageSize }}{% if SearchQueryEscaped %}&q={{ SearchQueryEscaped }}{% endif %}\">{{ Item.Page }}</a>\n    {% endif %}\n    {% endfor %}\n\n    {% if not Pager.HasNext() %}\n    <span class=\"page-link page-link-next\">下一页</span>\n    {% else %}\n    <a class=\"page-link page-link-next\" href=\"?page={{ Pager.NextPage() }}&pageSize={{ Pager.PageSize }}{% if SearchQueryEscaped %}&q={{ SearchQueryEscaped }}{% endif %}\">下一页</a>\n    {% endif %}\n  </div>\n  {% endif %}\n</nav>\n","inc_read_uv.html":"<span class=\"read-uv\" title=\"阅读数\">\n  {{ LucideIcon(\"book-open-check\", 16) }}\n  <span>{% if Count %}{{ Count }}{% else %}0{% endif %}</span>\n</span>\n","layout_main.html":"<!doctype html>\n<html lang=\"{{ Settings(''language'') }}\" data-route=\"{{ RouteName }}\">\n<head>\n  <meta charset=\"utf-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <title>{{ Title }}</title>\n  {% include \"inc_meta.html\" %}\n  {% include \"include/favicon.html\" %}\n\n  <link rel=\"stylesheet\" href=\"/static/site/tufte-css/tufte.min.css\">\n  <link rel=\"stylesheet\" href=\"/static/site/style.css\">\n  <script src=\"/static/site/main.js\"></script>\n\n  {% if Settings(\"ga4_id\") %}\n    {% include \"inc_ga.html\" %}\n  {% endif %}\n  {% block head_extra %}{% endblock %}\n</head>\n<body>\n  <main>\n      {% block content %}{% endblock %}\n  </main>\n\n  <footer>\n    <p>\n      <small>{{ (Settings(\"site_copyright\") or \"@copyright \" ~ Settings(\"author\")) | datetimeReplacer }}</small>\n    </p>\n  </footer>\n</body>\n</html>\n","list.html":"{% extends \"layout_main.html\" %}\n{% block content %}\n{% macro RenderCategoryTreeNodes(Nodes) %}\n  {% for CategoryNode in Nodes %}\n  <li>\n    <a href=\"{{ CategoryNode.Item.PermLink }}\">{{ CategoryNode.Item.Name }}</a>\n    <span class=\"post-count\">({{ CategoryNode.Item.PostCount }})</span>\n    <span>{{ CategoryNode.Item.CreatedAt | relativeTime }}</span>\n    {% if (CategoryNode.Children|length) > 0 %}\n    <ul>\n      {{ RenderCategoryTreeNodes(CategoryNode.Children) }}\n    </ul>\n    {% endif %}\n  </li>\n  {% endfor %}\n{% endmacro %}\n\n<header>\n  <h1>{{ Title }}</h1>\n\n  {% set PrevIsCategory = IsCategory %}\n  {% set PrevIsTag = IsTag %}\n  {% set IsCategory = true %}\n  {% set IsTag = true %}\n  {% include \"inc_list_nav.html\" %}\n  {% set IsCategory = PrevIsCategory %}\n  {% set IsTag = PrevIsTag %}\n</header>\n\n\n\n{% if IsCategory %}\n<ul class=\"category-index\">\n  {% if (List|length) > 0 %}\n    {{ RenderCategoryTreeNodes(List) }}\n  {% else %}\n  <li>暂无分类</li>\n  {% endif %}\n</ul>\n{% else %}\n<ul class=\"tag-index\">\n  {% for Tag in List %}\n  <li>\n    <a href=\"{{ Tag.PermLink }}\">{{ Tag.Name }}</a>\n    <span class=\"post-count\">({{ Tag.PostCount }})</span>\n    <span>{{ Tag.CreatedAt | relativeTime }}</span>\n  </li>\n  {% else %}\n  <li>暂无数据</li>\n  {% endfor %}\n</ul>\n{% endif %}\n{% endblock %}\n","macro_content.html":"{% macro CategoryItem(Item, Label=false, Sep=\"\") -%}\n  {% if Item %}\n    <span>\n    {% if Label %}分类{% endif %}{{ Sep }} <a href=\"{{ Item.PermLink }}\">{{ Item.Name }}</a>\n    </span>\n  {% endif %}\n{%- endmacro %}\n\n{% macro TagList(Items, Label=false, Sep=\"\") -%}\n  {% if Items and (Items|length) > 0 %}\n    <span>\n    {% if Label %}标签{% endif %}{{ Sep }}\n    {% set TagSep = joiner(\", \") %}\n    {% for Item in Items %}{{ TagSep() }}<a href=\"{{ Item.PermLink }}\">{{ Item.Name }}</a>{% endfor %}\n    </span>\n  {% endif %}\n{%- endmacro %}\n","post.html":"{% extends \"layout_main.html\" %}\n{% block content %}\n{% from \"macro_content.html\" import CategoryItem, TagList %}\n\n<header>\n  <h1>{{ Post.Title }}</h1>\n  <nav class=\"valign\">\n    <span class=\"author\">{{ Settings(\"author\") }}</span>\n    <span>{{ Post.PublishedAt | articleTime }}</span>\n    <a href=\"{{ GetBasePath() }}\">首页</a>\n    {% if IsLogin and (Post.ID > 0) %}\n      <a href=\"{{ UrlFor(''dash.posts.edit'', id=Post.ID) }}\">编辑</a>\n    {% endif %}\n    {% set Count = ReadUV %}\n    {% include \"inc_read_uv.html\" %}\n    {% if Post.Kind == 0 %}\n      {% set Count = CommentCount %}\n      {% include \"inc_comment_count.html\" %}\n    {% endif %}\n    {% set PostID = Post.ID %}\n    {% include \"inc_like_action.html\" %}\n  </nav>\n</header>\n<article>\n  <section>\n    {{ Post.HTML | safe }}\n  </section>\n</article>\n{% if Post.Kind == 0 %}\n<section>\n  <hr>\n  <div class=\"post-info\">\n    <div class=\"post-category-tag\">\n      <div>\n        {% if Post.Category %}\n          {{ CategoryItem(Post.Category, Label=true, Sep=\"：\") }}\n        {% else %}\n          <span>分类：无</span>\n        {% endif %}\n      </div>\n      <div>\n        {% if Post.Tags %}\n          {{ TagList(Post.Tags, Label=true, Sep=\"：\") }}\n        {% else %}\n          <span>标签：无</span>\n        {% endif %}\n      </div>\n    </div>\n    <div class=\"post-nav\">\n      <div>\n        {% if Post.Next %}\n          <span>上一篇：<a href=\"{{ Post.Next.PermLink }}\" class=\"next\">{{ Post.Next.Title }}</a></span>\n        {% else %}\n          <span>上一篇：无</span>\n        {% endif %}\n      </div>\n      <div>\n        {% if Post.Prev %}\n          <span>下一篇：<a href=\"{{ Post.Prev.PermLink }}\" class=\"prev\">{{ Post.Prev.Title }}</a></span>\n        {% else %}\n          <span>下一篇：无</span>\n        {% endif %}\n      </div>\n    </div>\n  </div>\n  <hr>\n</section>\n{% endif %}\n{% if Post.Kind == 0 %}\n  <section>\n  </section>\n{% endif %}\n\n\n\n  {% if Post.CommentEnabled == 1 %}\n  <section>\n  <footer>\n    <div id=\"comments\" class=\"comment-block\">\n      <h2 class=\"comment-title\">评论 ({{ CommentCount }})</h2>\n      {% if CommentFeedback == \"approved\" %}\n{#        <p class=\"comment-feedback\"><small>评论已发布。</small></p>#}\n      {% elif CommentFeedback == \"pending\" %}\n        <p class=\"comment-feedback\"><small>评论已提交，等待审核。</small></p>\n      {% elif CommentFeedback == \"captcha_required\" %}\n        <p class=\"comment-feedback\"><small>提交较频繁，请先完成验证码再继续评论。</small></p>\n      {% elif CommentFeedback == \"captcha_failed\" %}\n        <p class=\"comment-feedback\"><small>验证码错误或已过期，请刷新页面后重试。</small></p>\n      {% elif CommentFeedback == \"rate_limited\" %}\n        <p class=\"comment-feedback\"><small>提交过于频繁，请稍后再试。</small></p>\n      {% elif CommentFeedback == \"duplicate\" %}\n        <p class=\"comment-feedback\"><small>请勿重复提交相同评论内容。</small></p>\n      {% endif %}\n\n      {% if Comments %}\n        <ol class=\"comment-list\">\n          {% for Item in Comments %}\n            {% set Comment = Item %}\n            {% include \"inc_comment_item.html\" %}\n          {% endfor %}\n        </ol>\n      {% else %}\n        <p class=\"comment-empty\"><small>暂无评论，欢迎抢沙发。</small></p>\n      {% endif %}\n      {% if CommentPager and CommentPager.Num > 1 %}\n        {% set Pager = CommentPager %}\n        {% include \"inc_comment_pagination.html\" %}\n      {% endif %}\n\n      <fieldset>\n        <legend>发表评论</legend>\n        <form method=\"post\" action=\"{{ UrlFor(''site.action.comment'', postID=Post.ID) }}\" id=\"comment-form\" class=\"comment-form\">\n          <input type=\"hidden\" name=\"return_url\" value=\"{{ UrlPath }}\">\n          <input type=\"hidden\" name=\"parent_id\" value=\"0\" id=\"comment-parent-id\">\n          <p class=\"comment-form-row\">\n            <label for=\"comment-author\">昵称</label>\n            <input id=\"comment-author\" class=\"comment-input\" name=\"author\" type=\"text\" required maxlength=\"80\" value=\"{{ CommentForm.Author }}\">\n          </p>\n          <p class=\"comment-form-row\">\n            <label for=\"comment-email\">邮箱</label>\n            <input id=\"comment-email\" class=\"comment-input\" name=\"author_email\" type=\"email\" maxlength=\"120\" placeholder=\"可选\" value=\"{{ CommentForm.AuthorEmail }}\">\n            <small class=\"comment-help\">填写后可自动显示 Gravatar 头像服务中的头像。</small>\n          </p>\n          <p class=\"comment-form-row\">\n            <label for=\"comment-url\">网址</label>\n            <input id=\"comment-url\" class=\"comment-input\" name=\"author_url\" type=\"url\" maxlength=\"300\" placeholder=\"可选\" value=\"{{ CommentForm.AuthorURL }}\">\n          </p>\n          <p class=\"comment-form-row\">\n            <label for=\"comment-content\">内容</label>\n            <textarea id=\"comment-content\" class=\"comment-textarea\" name=\"content\" rows=\"8\" cols=\"40\" minlength=\"5\" maxlength=\"5000\" required>{{ CommentForm.Content }}</textarea>\n          </p>\n          <p class=\"comment-form-row comment-remember\">\n            <label for=\"comment-remember-me\" class=\"comment-checkbox-label\">\n              <input id=\"comment-remember-me\" name=\"remember_me\" type=\"checkbox\" value=\"1\"{% if CommentForm.RememberMe %} checked{% endif %}>\n              <span>记住我</span>\n            </label>\n          </p>\n          {% if CommentCaptchaRequired %}\n            <p class=\"comment-form-row\">\n              <label for=\"comment-captcha-answer\">验证码</label>\n              <span class=\"comment-captcha-wrap\">\n                <span>{{ CommentCaptcha.Prompt }}</span>\n                <input id=\"comment-captcha-answer\" class=\"comment-input\" name=\"captcha_answer\" type=\"text\" inputmode=\"numeric\" pattern=\"[0-9]+\" maxlength=\"16\" required autocomplete=\"off\">\n              </span>\n              <input type=\"hidden\" name=\"captcha_token\" value=\"{{ CommentCaptcha.Token }}\">\n            </p>\n          {% endif %}\n          <p id=\"comment-reply-state\" class=\"comment-form-row comment-reply-state\" hidden>\n            <small>回复 @<span id=\"comment-reply-author\"></span></small>\n            <button type=\"button\" id=\"comment-reply-cancel\" class=\"comment-link-btn\">取消回复</button>\n          </p>\n          <div class=\"comment-submit-row\">\n            <button type=\"submit\">提交评论</button>\n          </div>\n        </form>\n      </fieldset>\n    </div>\n  </footer>\n  </section>\n{% else %}\n  <section>\n  <footer>\n    <div id=\"comments\" class=\"comment-block\">\n      <h2 class=\"comment-title\">评论</h2>\n      <p class=\"comment-empty\"><small>评论已关闭。</small></p>\n    </div>\n  </footer>\n  </section>\n{% endif %}\n\n<script>\n  (function () {\n    var root = document.getElementById(\"comments\");\n    if (!root) return;\n\n    var parentInput = document.getElementById(\"comment-parent-id\");\n    var replyState = document.getElementById(\"comment-reply-state\");\n    var replyAuthor = document.getElementById(\"comment-reply-author\");\n    var cancelBtn = document.getElementById(\"comment-reply-cancel\");\n\n    function resetReply() {\n      parentInput.value = \"0\";\n      replyAuthor.textContent = \"\";\n      if (replyState) {\n        replyState.hidden = true;\n      }\n    }\n\n    root.addEventListener(\"click\", function (event) {\n      var trigger = event.target.closest(\"[data-comment-reply]\");\n      if (!trigger) return;\n      event.preventDefault();\n\n      var commentID = trigger.getAttribute(\"data-comment-id\");\n      var author = trigger.getAttribute(\"data-comment-author\") || \"\";\n      if (!commentID) return;\n\n      parentInput.value = commentID;\n      replyAuthor.textContent = author;\n      if (replyState) {\n        replyState.hidden = false;\n      }\n      document.getElementById(\"comment-content\").focus();\n    });\n\n    if (cancelBtn) {\n      cancelBtn.addEventListener(\"click\", function () {\n        resetReply();\n      });\n    }\n  })();\n</script>\n{% include \"include/math.html\" %}\n{% endblock %}\n"}',
    current_file = 'home.html',
    status = 'draft',
    is_builtin = 1,
    updated_at = strftime('%s','now')
WHERE code = 'tuft' AND deleted_at IS NULL;

INSERT INTO t_themes (
    name,
    code,
    description,
    author,
    files,
    current_file,
    status,
    is_current,
    is_builtin,
    version,
    created_at,
    updated_at
)
SELECT
    'tuft',
    'tuft',
    '内置默认主题',
    'swaves',
    '{"404.html":"{% extends \"layout_main.html\" %}\n{% block content %}\n<header>\n  <h1>页面找不到</h1>\n  <p>页面不存在，可能已被删除或地址写错了。</p>\n</header>\n\n<article>\n  <p>\n    返回 <a href=\"{{ ReturnURL }}\">来源页</a>重试，\n    或者返回 <a href=\"{{ GetBasePath() }}\">首页</a>\n  </p>\n  {% if ReqID %}<p><small>请求ID: {{ ReqID }}</small></p>{% endif %}\n</article>\n{% endblock %}\n","detail.html":"{% extends \"layout_main.html\" %}\n{% block content %}\n{% from \"macro_content.html\" import CategoryItem, TagList %}\n\n<header>\n  <h1>{{ Entity.Name }}</h1>\n\n  {% include \"inc_list_nav.html\" %}\n</header>\n\n{% if Entity.Description %}\n<section>\n  <p class=\"subtitle\">{{ Entity.Description }}</p>\n</section>\n{% endif %}\n\n<ul>\n  {% for Item in List %}\n  <li>\n    <a href=\"{{ Item.PermLink }}\">{{ Item.Title }}</a>\n    <span class=\"relation\">\n      {{ TagList(Item.Tags, true) }}\n      {% if (not IsCategory) and Item.Category %}\n        {{ CategoryItem(Item.Category, true) }}\n      {% endif %}\n    </span>\n    <span class=\"published\">{{ Item.CreatedAt | relativeTime }}</span>\n  </li>\n  {% else %}\n  <li>暂无文章</li>\n  {% endfor %}\n</ul>\n{% endblock %}\n","error.html":"{% extends \"layout_main.html\" %}\n{% block content %}\n<header>\n  <h1>页面异常</h1>\n  <p>请求处理失败，请稍后重试。</p>\n</header>\n\n<article>\n  <p>\n    <a href=\"{{ ReturnURL }}\">返回来源页，重试</a>\n    或者 <a href=\"{{ GetBasePath() }}\">返回首页</a>\n  </p>\n  {% if ReqID %}<p><small>请求ID: {{ ReqID }}</small></p>{% endif %}\n</article>\n{% endblock %}\n","home.html":"{% extends \"layout_main.html\" %}\n{% block content %}\n<header>\n  <h1>{{ Settings(\"site_title\") }}</h1>\n  {% include \"inc_nav.html\" %}\n</header>\n\n<section>\n<ul class=\"articles\">\n  {% for Article in Articles %}\n  <li>\n    <a href=\"{{ Article.PermLink }}\">{{ Article.Title }}</a>\n    <span class=\"published\">{{ Article.PublishedAt | relativeTime }}</span>\n  </li>\n  {% else %}\n  <li>暂无文章</li>\n  {% endfor %}\n</ul>\n</section>\n\n{% include \"inc_pagination.html\" %}\n{% endblock %}\n","inc_comment_count.html":"<a class=\"comment-count\" href=\"#comments\" title=\"评论数\" aria-label=\"评论数\">\n  {{ LucideIcon(\"message-square\", 16) }}\n  <span>{% if Count %}{{ Count }}{% else %}0{% endif %}</span>\n</a>\n","inc_comment_item.html":"{% set CommentCore = Comment.Comment or Comment %}\n{% set CommentParentAuthor = Comment.ParentAuthor or CommentCore.ParentAuthor %}\n{% set CommentChildren = Comment.Children %}\n<li class=\"comment-item\" id=\"comment-{{ CommentCore.ID }}\">\n  <div class=\"comment-card\">\n    <header class=\"comment-meta\">\n      <div class=\"comment-info\">\n        <img\n          class=\"comment-avatar\"\n          src=\"{{ GetAvatarImage(CommentCore.AuthorEmail, CommentCore.Author, 40) }}\"\n          alt=\"{{ CommentCore.Author }}\"\n          width=\"40\"\n          height=\"40\"\n        >\n        <div class=\"comment-meta-main\">\n          <strong class=\"comment-author\">{{ CommentCore.Author }}</strong>\n          <small class=\"comment-time\">· {{ CommentCore.CreatedAt | relativeTime }}</small>\n          {% if CommentCore.ParentID > 0 %}\n            <small class=\"comment-reply-to\">· 回复 @{{ CommentParentAuthor }}</small>\n          {% endif %}\n        </div>\n      </div>\n      <div class=\"comment-actions\">\n        <button\n                type=\"button\"\n                class=\"comment-reply-btn\"\n                data-comment-reply\n                data-comment-id=\"{{ CommentCore.ID }}\"\n                data-comment-author=\"{{ CommentCore.Author }}\"\n        >回复</button>\n      </div>\n    </header>\n    <div class=\"comment-body\">{{ CommentCore.Content }}</div>\n  </div>\n  {% if CommentChildren %}\n    <ol class=\"comment-children\">\n      {% for ChildComment in CommentChildren %}\n        {% set Comment = ChildComment %}\n        {% include \"inc_comment_item.html\" %}\n      {% endfor %}\n    </ol>\n  {% endif %}\n</li>\n","inc_comment_pagination.html":"<nav aria-label=\"评论分页导航\" class=\"pagination comment-pagination\">\n  {% if Pager %}\n    <div class=\"ivalign gap-1\">\n      {% if not Pager.HasPrev() %}\n        <span class=\"page-link page-link-prev\" tabindex=\"-1\">上一页</span>\n      {% else %}\n        <a class=\"page-link page-link-prev\" href=\"?page={{ Pager.PrevPage() }}&pageSize={{ Pager.PageSize }}#comments\" tabindex=\"-1\">上一页</a>\n      {% endif %}\n\n      {% for Item in Pager.GetPageItems() %}\n        {% if Item.Type == \"ellipsis\" %}\n          <span class=\"page-link\" aria-hidden=\"true\">…</span>\n        {% elif Item.Current %}\n          <span class=\"page-link\">{{ Item.Page }}</span>\n        {% else %}\n          <a class=\"page-link-num page-link\" href=\"?page={{ Item.Page }}&pageSize={{ Pager.PageSize }}#comments\">{{ Item.Page }}</a>\n        {% endif %}\n      {% endfor %}\n\n      {% if not Pager.HasNext() %}\n        <span class=\"page-link page-link-next\">下一页</span>\n      {% else %}\n        <a class=\"page-link page-link-next\" href=\"?page={{ Pager.NextPage() }}&pageSize={{ Pager.PageSize }}#comments\">下一页</a>\n      {% endif %}\n    </div>\n  {% endif %}\n</nav>\n","inc_ga.html":"<script async=\"\" src=\"https://www.googletagmanager.com/gtag/js?id={{ Settings(\"ga4_id\") }}\"></script><script>\n  window.dataLayer = window.dataLayer || [];\n  function gtag(){dataLayer.push(arguments);}\n  gtag(''js'', new Date());\n  gtag(''config'', ''{{ Settings(\"ga4_id\") }}'');\n</script>\n","inc_like_action.html":"<form method=\"post\" action=\"{{ UrlFor(''site.action.like'', postID=PostID) }}\" style=\"display:inline-flex;align-items: center\" data-like-form>\n  <input type=\"hidden\" name=\"return_url\" value=\"{{ UrlPath }}\">\n  <button title=\"点赞数\" type=\"submit\" data-like-button data-liked=\"{% if Liked %}1{% else %}0{% endif %}\" aria-label=\"点赞\">\n    {{ LucideIcon(\"heart\", 16) }}\n    <span data-like-count>{% if LikeCount %}{{ LikeCount }}{% else %}0{% endif %}</span>\n  </button>\n</form>\n<script>\n  (function () {\n    if (window.__swavesLikeAsyncInit) {\n      return;\n    }\n    window.__swavesLikeAsyncInit = true;\n\n    function toLikeCount(value) {\n      var count = Number.parseInt(value, 10);\n      if (Number.isNaN(count) || count < 0) {\n        return 0;\n      }\n      return count;\n    }\n\n    function updateLikeButton(button, likeCount, liked) {\n      var countEl = button.querySelector(\"[data-like-count]\");\n      if (countEl) {\n        countEl.textContent = String(likeCount);\n      }\n      button.dataset.liked = liked ? \"1\" : \"0\";\n    }\n\n    async function handleLikeSubmit(event) {\n      event.preventDefault();\n\n      var form = event.currentTarget;\n      var button = form.querySelector(\"[data-like-button]\");\n      if (!button || button.disabled) {\n        return;\n      }\n\n      var countEl = button.querySelector(\"[data-like-count]\");\n      var previousCount = countEl ? countEl.textContent : \"\";\n      var previousLiked = button.dataset.liked || \"0\";\n      button.disabled = true;\n\n      try {\n        var ret = await sfetchJSON(form.action, {\n          method: \"POST\",\n          body: new FormData(form)\n        });\n\n        if (!ret.ok || !ret.body) {\n          throw new Error(\"点赞请求失败\");\n        }\n        var result = ret.body;\n        updateLikeButton(button, toLikeCount(result.likeCount), !!result.liked);\n      } catch (error) {\n        if (countEl) {\n          countEl.textContent = previousCount;\n        }\n        button.dataset.liked = previousLiked;\n        if (window.console && typeof window.console.warn === \"function\") {\n          window.console.warn(\"like request failed\", error);\n        }\n      } finally {\n        button.disabled = false;\n      }\n    }\n\n    var forms = document.querySelectorAll(\"[data-like-form]\");\n    forms.forEach(function (form) {\n      form.addEventListener(\"submit\", handleLikeSubmit);\n    });\n  })();\n</script>\n","inc_list_nav.html":"<nav>\n  <a href=\"{{ GetBasePath() }}\">首页</a>\n    {% if IsCategory %}\n      / <a href=\"{{ GetCategoryPrefix() }}\">分类</a>\n    {% endif %}\n    {% if IsTag %}\n      / <a href=\"{{ GetTagPrefix() }}\">标签</a>\n    {% endif %}\n</nav>\n","inc_meta.html":"  {% if MetaDescription or Settings(''site_desc'') %}<meta name=\"description\" content=\"{{ MetaDescription or Settings(''site_desc'') }}\"/>{% endif %}\n  {% if MetaKeywords or Settings(''site_keywords'') %}<meta name=\"keywords\" content=\"{{ MetaKeywords or Settings(''site_keywords'') }}\"/>{% endif %}\n  {% if CanonicalURL %}<link rel=\"canonical\" href=\"{{ CanonicalURL | safe }}\">{% endif %}\n","inc_nav.html":"<nav>\n  <a href=\"{{ GetBasePath() }}\">首页</a>\n  /\n  <a href=\"{{ GetCategoryPrefix() }}\">分类</a>\n  /\n  <a href=\"{{ GetTagPrefix() }}\">标签</a>\n  {% if Pages %}\n    {% for Page in Pages %}\n      / <a href=\"{{ Page.PermLink }}\">{{ Page.Title }}</a>\n    {% endfor %}\n  {% endif %}\n  / <a href=\"{{ GetRSSUrl() }}\">RSS</a>\n  {% if IsLogin %}\n    / <a href=\"{{ GetDashUrl() }}\">管理</a>\n  {% endif %}\n</nav>\n","inc_pagination.html":"<nav aria-label=\"分页导航\" class=\"pagination\">\n  {% if Pager %}\n  <div class=\"ivalign gap-1\">\n    {% if not Pager.HasPrev() %}\n    <span class=\"page-link page-link-prev\" tabindex=\"-1\">上一页</span>\n    {% else %}\n    <a class=\"page-link page-link-prev\" href=\"?page={{ Pager.PrevPage() }}&pageSize={{ Pager.PageSize }}{% if SearchQueryEscaped %}&q={{ SearchQueryEscaped }}{% endif %}\" tabindex=\"-1\">上一页</a>\n    {% endif %}\n\n    {% for Item in Pager.GetPageItems() %}\n    {% if Item.Type == \"ellipsis\" %}\n    <span class=\"page-link\" aria-hidden=\"true\">…</span>\n    {% elif Item.Current %}\n    <span class=\"page-link\">{{ Item.Page }}</span>\n    {% else %}\n    <a class=\"page-link-num page-link\" href=\"?page={{ Item.Page }}&pageSize={{ Pager.PageSize }}{% if SearchQueryEscaped %}&q={{ SearchQueryEscaped }}{% endif %}\">{{ Item.Page }}</a>\n    {% endif %}\n    {% endfor %}\n\n    {% if not Pager.HasNext() %}\n    <span class=\"page-link page-link-next\">下一页</span>\n    {% else %}\n    <a class=\"page-link page-link-next\" href=\"?page={{ Pager.NextPage() }}&pageSize={{ Pager.PageSize }}{% if SearchQueryEscaped %}&q={{ SearchQueryEscaped }}{% endif %}\">下一页</a>\n    {% endif %}\n  </div>\n  {% endif %}\n</nav>\n","inc_read_uv.html":"<span class=\"read-uv\" title=\"阅读数\">\n  {{ LucideIcon(\"book-open-check\", 16) }}\n  <span>{% if Count %}{{ Count }}{% else %}0{% endif %}</span>\n</span>\n","layout_main.html":"<!doctype html>\n<html lang=\"{{ Settings(''language'') }}\" data-route=\"{{ RouteName }}\">\n<head>\n  <meta charset=\"utf-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <title>{{ Title }}</title>\n  {% include \"inc_meta.html\" %}\n  {% include \"include/favicon.html\" %}\n\n  <link rel=\"stylesheet\" href=\"/static/site/tufte-css/tufte.min.css\">\n  <link rel=\"stylesheet\" href=\"/static/site/style.css\">\n  <script src=\"/static/site/main.js\"></script>\n\n  {% if Settings(\"ga4_id\") %}\n    {% include \"inc_ga.html\" %}\n  {% endif %}\n  {% block head_extra %}{% endblock %}\n</head>\n<body>\n  <main>\n      {% block content %}{% endblock %}\n  </main>\n\n  <footer>\n    <p>\n      <small>{{ (Settings(\"site_copyright\") or \"@copyright \" ~ Settings(\"author\")) | datetimeReplacer }}</small>\n    </p>\n  </footer>\n</body>\n</html>\n","list.html":"{% extends \"layout_main.html\" %}\n{% block content %}\n{% macro RenderCategoryTreeNodes(Nodes) %}\n  {% for CategoryNode in Nodes %}\n  <li>\n    <a href=\"{{ CategoryNode.Item.PermLink }}\">{{ CategoryNode.Item.Name }}</a>\n    <span class=\"post-count\">({{ CategoryNode.Item.PostCount }})</span>\n    <span>{{ CategoryNode.Item.CreatedAt | relativeTime }}</span>\n    {% if (CategoryNode.Children|length) > 0 %}\n    <ul>\n      {{ RenderCategoryTreeNodes(CategoryNode.Children) }}\n    </ul>\n    {% endif %}\n  </li>\n  {% endfor %}\n{% endmacro %}\n\n<header>\n  <h1>{{ Title }}</h1>\n\n  {% set PrevIsCategory = IsCategory %}\n  {% set PrevIsTag = IsTag %}\n  {% set IsCategory = true %}\n  {% set IsTag = true %}\n  {% include \"inc_list_nav.html\" %}\n  {% set IsCategory = PrevIsCategory %}\n  {% set IsTag = PrevIsTag %}\n</header>\n\n\n\n{% if IsCategory %}\n<ul class=\"category-index\">\n  {% if (List|length) > 0 %}\n    {{ RenderCategoryTreeNodes(List) }}\n  {% else %}\n  <li>暂无分类</li>\n  {% endif %}\n</ul>\n{% else %}\n<ul class=\"tag-index\">\n  {% for Tag in List %}\n  <li>\n    <a href=\"{{ Tag.PermLink }}\">{{ Tag.Name }}</a>\n    <span class=\"post-count\">({{ Tag.PostCount }})</span>\n    <span>{{ Tag.CreatedAt | relativeTime }}</span>\n  </li>\n  {% else %}\n  <li>暂无数据</li>\n  {% endfor %}\n</ul>\n{% endif %}\n{% endblock %}\n","macro_content.html":"{% macro CategoryItem(Item, Label=false, Sep=\"\") -%}\n  {% if Item %}\n    <span>\n    {% if Label %}分类{% endif %}{{ Sep }} <a href=\"{{ Item.PermLink }}\">{{ Item.Name }}</a>\n    </span>\n  {% endif %}\n{%- endmacro %}\n\n{% macro TagList(Items, Label=false, Sep=\"\") -%}\n  {% if Items and (Items|length) > 0 %}\n    <span>\n    {% if Label %}标签{% endif %}{{ Sep }}\n    {% set TagSep = joiner(\", \") %}\n    {% for Item in Items %}{{ TagSep() }}<a href=\"{{ Item.PermLink }}\">{{ Item.Name }}</a>{% endfor %}\n    </span>\n  {% endif %}\n{%- endmacro %}\n","post.html":"{% extends \"layout_main.html\" %}\n{% block content %}\n{% from \"macro_content.html\" import CategoryItem, TagList %}\n\n<header>\n  <h1>{{ Post.Title }}</h1>\n  <nav class=\"valign\">\n    <span class=\"author\">{{ Settings(\"author\") }}</span>\n    <span>{{ Post.PublishedAt | articleTime }}</span>\n    <a href=\"{{ GetBasePath() }}\">首页</a>\n    {% if IsLogin and (Post.ID > 0) %}\n      <a href=\"{{ UrlFor(''dash.posts.edit'', id=Post.ID) }}\">编辑</a>\n    {% endif %}\n    {% set Count = ReadUV %}\n    {% include \"inc_read_uv.html\" %}\n    {% if Post.Kind == 0 %}\n      {% set Count = CommentCount %}\n      {% include \"inc_comment_count.html\" %}\n    {% endif %}\n    {% set PostID = Post.ID %}\n    {% include \"inc_like_action.html\" %}\n  </nav>\n</header>\n<article>\n  <section>\n    {{ Post.HTML | safe }}\n  </section>\n</article>\n{% if Post.Kind == 0 %}\n<section>\n  <hr>\n  <div class=\"post-info\">\n    <div class=\"post-category-tag\">\n      <div>\n        {% if Post.Category %}\n          {{ CategoryItem(Post.Category, Label=true, Sep=\"：\") }}\n        {% else %}\n          <span>分类：无</span>\n        {% endif %}\n      </div>\n      <div>\n        {% if Post.Tags %}\n          {{ TagList(Post.Tags, Label=true, Sep=\"：\") }}\n        {% else %}\n          <span>标签：无</span>\n        {% endif %}\n      </div>\n    </div>\n    <div class=\"post-nav\">\n      <div>\n        {% if Post.Next %}\n          <span>上一篇：<a href=\"{{ Post.Next.PermLink }}\" class=\"next\">{{ Post.Next.Title }}</a></span>\n        {% else %}\n          <span>上一篇：无</span>\n        {% endif %}\n      </div>\n      <div>\n        {% if Post.Prev %}\n          <span>下一篇：<a href=\"{{ Post.Prev.PermLink }}\" class=\"prev\">{{ Post.Prev.Title }}</a></span>\n        {% else %}\n          <span>下一篇：无</span>\n        {% endif %}\n      </div>\n    </div>\n  </div>\n  <hr>\n</section>\n{% endif %}\n{% if Post.Kind == 0 %}\n  <section>\n  </section>\n{% endif %}\n\n\n\n  {% if Post.CommentEnabled == 1 %}\n  <section>\n  <footer>\n    <div id=\"comments\" class=\"comment-block\">\n      <h2 class=\"comment-title\">评论 ({{ CommentCount }})</h2>\n      {% if CommentFeedback == \"approved\" %}\n{#        <p class=\"comment-feedback\"><small>评论已发布。</small></p>#}\n      {% elif CommentFeedback == \"pending\" %}\n        <p class=\"comment-feedback\"><small>评论已提交，等待审核。</small></p>\n      {% elif CommentFeedback == \"captcha_required\" %}\n        <p class=\"comment-feedback\"><small>提交较频繁，请先完成验证码再继续评论。</small></p>\n      {% elif CommentFeedback == \"captcha_failed\" %}\n        <p class=\"comment-feedback\"><small>验证码错误或已过期，请刷新页面后重试。</small></p>\n      {% elif CommentFeedback == \"rate_limited\" %}\n        <p class=\"comment-feedback\"><small>提交过于频繁，请稍后再试。</small></p>\n      {% elif CommentFeedback == \"duplicate\" %}\n        <p class=\"comment-feedback\"><small>请勿重复提交相同评论内容。</small></p>\n      {% endif %}\n\n      {% if Comments %}\n        <ol class=\"comment-list\">\n          {% for Item in Comments %}\n            {% set Comment = Item %}\n            {% include \"inc_comment_item.html\" %}\n          {% endfor %}\n        </ol>\n      {% else %}\n        <p class=\"comment-empty\"><small>暂无评论，欢迎抢沙发。</small></p>\n      {% endif %}\n      {% if CommentPager and CommentPager.Num > 1 %}\n        {% set Pager = CommentPager %}\n        {% include \"inc_comment_pagination.html\" %}\n      {% endif %}\n\n      <fieldset>\n        <legend>发表评论</legend>\n        <form method=\"post\" action=\"{{ UrlFor(''site.action.comment'', postID=Post.ID) }}\" id=\"comment-form\" class=\"comment-form\">\n          <input type=\"hidden\" name=\"return_url\" value=\"{{ UrlPath }}\">\n          <input type=\"hidden\" name=\"parent_id\" value=\"0\" id=\"comment-parent-id\">\n          <p class=\"comment-form-row\">\n            <label for=\"comment-author\">昵称</label>\n            <input id=\"comment-author\" class=\"comment-input\" name=\"author\" type=\"text\" required maxlength=\"80\" value=\"{{ CommentForm.Author }}\">\n          </p>\n          <p class=\"comment-form-row\">\n            <label for=\"comment-email\">邮箱</label>\n            <input id=\"comment-email\" class=\"comment-input\" name=\"author_email\" type=\"email\" maxlength=\"120\" placeholder=\"可选\" value=\"{{ CommentForm.AuthorEmail }}\">\n            <small class=\"comment-help\">填写后可自动显示 Gravatar 头像服务中的头像。</small>\n          </p>\n          <p class=\"comment-form-row\">\n            <label for=\"comment-url\">网址</label>\n            <input id=\"comment-url\" class=\"comment-input\" name=\"author_url\" type=\"url\" maxlength=\"300\" placeholder=\"可选\" value=\"{{ CommentForm.AuthorURL }}\">\n          </p>\n          <p class=\"comment-form-row\">\n            <label for=\"comment-content\">内容</label>\n            <textarea id=\"comment-content\" class=\"comment-textarea\" name=\"content\" rows=\"8\" cols=\"40\" minlength=\"5\" maxlength=\"5000\" required>{{ CommentForm.Content }}</textarea>\n          </p>\n          <p class=\"comment-form-row comment-remember\">\n            <label for=\"comment-remember-me\" class=\"comment-checkbox-label\">\n              <input id=\"comment-remember-me\" name=\"remember_me\" type=\"checkbox\" value=\"1\"{% if CommentForm.RememberMe %} checked{% endif %}>\n              <span>记住我</span>\n            </label>\n          </p>\n          {% if CommentCaptchaRequired %}\n            <p class=\"comment-form-row\">\n              <label for=\"comment-captcha-answer\">验证码</label>\n              <span class=\"comment-captcha-wrap\">\n                <span>{{ CommentCaptcha.Prompt }}</span>\n                <input id=\"comment-captcha-answer\" class=\"comment-input\" name=\"captcha_answer\" type=\"text\" inputmode=\"numeric\" pattern=\"[0-9]+\" maxlength=\"16\" required autocomplete=\"off\">\n              </span>\n              <input type=\"hidden\" name=\"captcha_token\" value=\"{{ CommentCaptcha.Token }}\">\n            </p>\n          {% endif %}\n          <p id=\"comment-reply-state\" class=\"comment-form-row comment-reply-state\" hidden>\n            <small>回复 @<span id=\"comment-reply-author\"></span></small>\n            <button type=\"button\" id=\"comment-reply-cancel\" class=\"comment-link-btn\">取消回复</button>\n          </p>\n          <div class=\"comment-submit-row\">\n            <button type=\"submit\">提交评论</button>\n          </div>\n        </form>\n      </fieldset>\n    </div>\n  </footer>\n  </section>\n{% else %}\n  <section>\n  <footer>\n    <div id=\"comments\" class=\"comment-block\">\n      <h2 class=\"comment-title\">评论</h2>\n      <p class=\"comment-empty\"><small>评论已关闭。</small></p>\n    </div>\n  </footer>\n  </section>\n{% endif %}\n\n<script>\n  (function () {\n    var root = document.getElementById(\"comments\");\n    if (!root) return;\n\n    var parentInput = document.getElementById(\"comment-parent-id\");\n    var replyState = document.getElementById(\"comment-reply-state\");\n    var replyAuthor = document.getElementById(\"comment-reply-author\");\n    var cancelBtn = document.getElementById(\"comment-reply-cancel\");\n\n    function resetReply() {\n      parentInput.value = \"0\";\n      replyAuthor.textContent = \"\";\n      if (replyState) {\n        replyState.hidden = true;\n      }\n    }\n\n    root.addEventListener(\"click\", function (event) {\n      var trigger = event.target.closest(\"[data-comment-reply]\");\n      if (!trigger) return;\n      event.preventDefault();\n\n      var commentID = trigger.getAttribute(\"data-comment-id\");\n      var author = trigger.getAttribute(\"data-comment-author\") || \"\";\n      if (!commentID) return;\n\n      parentInput.value = commentID;\n      replyAuthor.textContent = author;\n      if (replyState) {\n        replyState.hidden = false;\n      }\n      document.getElementById(\"comment-content\").focus();\n    });\n\n    if (cancelBtn) {\n      cancelBtn.addEventListener(\"click\", function () {\n        resetReply();\n      });\n    }\n  })();\n</script>\n{% include \"include/math.html\" %}\n{% endblock %}\n"}',
    'home.html',
    'draft',
    CASE
        WHEN EXISTS (
            SELECT 1 FROM t_themes WHERE is_current = 1 AND deleted_at IS NULL
        ) THEN 0
        ELSE 1
    END,
    1,
    1,
    strftime('%s','now'),
    strftime('%s','now')
WHERE NOT EXISTS (
    SELECT 1 FROM t_themes WHERE code = 'tuft' AND deleted_at IS NULL
);

UPDATE t_themes
SET is_current = 1,
    updated_at = strftime('%s','now')
WHERE code = 'tuft'
  AND deleted_at IS NULL
  AND NOT EXISTS (
      SELECT 1 FROM t_themes AS current_theme
      WHERE current_theme.is_current = 1
        AND current_theme.deleted_at IS NULL
        AND current_theme.code <> 'tuft'
  )
  AND NOT EXISTS (
      SELECT 1 FROM t_themes AS current_theme
      WHERE current_theme.is_current = 1
        AND current_theme.deleted_at IS NULL
        AND current_theme.code = 'tuft'
  );

COMMIT;
